ON CONFLICT (marketplace_product_id) DO UPDATE SET
  name_en = EXCLUDED.name_en,
  name_ar = EXCLUDED.name_ar,
  feed_type = EXCLUDED.feed_type,
  supplier_name = EXCLUDED.supplier_name,
  supplier_email = EXCLUDED.supplier_email,
  supplier_phone = EXCLUDED.supplier_phone,
  supplier_address = EXCLUDED.supplier_address,
  country_code = EXCLUDED.country_code,
  currency = EXCLUDED.currency,
  price_per_kg = EXCLUDED.price_per_kg,
  min_order_kg = EXCLUDED.min_order_kg,
  pack_size_kg = EXCLUDED.pack_size_kg,
  standard_product_number = EXCLUDED.standard_product_number,
  dm_percent = EXCLUDED.dm_percent,
  cp_percent = EXCLUDED.cp_percent,
  nem_mcal_kg = EXCLUDED.nem_mcal_kg,
  ndf_percent = EXCLUDED.ndf_percent,
  in_stock = EXCLUDED.in_stock,
  is_active = EXCLUDED.is_active,
  source = EXCLUDED.source,
  updated_at = NOW();

INSERT INTO marketplace_feed_product_trans (product_id, locale, name)
SELECT id, 'en', name_en FROM marketplace_feed_products
WHERE prod_id BETWEEN 3001 AND 3853
ON CONFLICT (product_id, locale) DO UPDATE SET name = EXCLUDED.name;

INSERT INTO marketplace_feed_product_trans (product_id, locale, name)
SELECT id, 'ar', name_ar FROM marketplace_feed_products
WHERE prod_id BETWEEN 3001 AND 3853 AND name_ar IS NOT NULL
ON CONFLICT (product_id, locale) DO UPDATE SET name = EXCLUDED.name;

COMMIT;
